use std::collections::HashSet;

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct ConnectionParam {
    protocol_name: String,
    fallback_value: u32,
}

fn check_all_validity(params: &Vec<ConnectionParam>) -> bool {
    let set = params.iter().map(|p| p.protocol_name.clone()).collect::<HashSet<_>>().len();
    if set != params.len() {
        return false;
    }
    params.iter().all(|p| p.fallback_value > 0)
}

fn attempt_connection(protocols: &Vec<String>) -> bool {
    for protocol in protocols {
        println!("Attempting connection with protocol: {}", protocol);
        if protocol == "TLS-1.3" || protocol == "TLS-1.2" {
            return true;
        }
    }
    false
}

fn main() {
    let initial_params = vec![
        ConnectionParam { protocol_name: "Unknown".to_string(), fallback_value: 10 },
        ConnectionParam { protocol_name: "Known".to_string(), fallback_value: 5 },
        ConnectionParam { protocol_name: "Unknown".to_string(), fallback_value: 20 },
    ];

    println!("Checking all parameters for consistency...");
    let all_ok = check_all_validity(&initial_params);
    println!("All parameters are consistently valid: {}", all_ok);

    let fallback_protocols = vec!["HTTP/1.1".to_string(), "TLS-1.3".to_string(), "QUIC".to_string()];

    println!("
Testing connection fallbacks...");
    let connected = attempt_connection(&fallback_protocols);
    println!("Successful connection established: {}", connected);
}

use std::collections::HashSet;

struct NetworkPacket {
    sequence_number: u32,
    has_auth_flag: bool,
    payload_data: Vec<u8>,
}

fn process_packets(packets: &Vec<NetworkPacket>) -> (bool, Vec<u32>) {
    let any_check: bool = packets.iter().any(|packet| packet.has_auth_flag);

    let valid_checksums: Vec<u32> = packets.iter()
        .filter(|packet| { 
            if packet.sequence_number % 2 == 0 {
                true
            } else {
                false
            }
        })
        .map(|packet| { 
            let mut checksum: u32 = 0;
            for byte in &packet.payload_data {
                checksum = checksum.wrapping_add(*byte as u32);
            }
            checksum
        }) 
        .collect();

    (any_check, valid_checksums)
}

fn main() {
    let packets = vec![ 
        NetworkPacket { sequence_number: 10, has_auth_flag: false, payload_data: vec![1, 2] }, 
        NetworkPacket { sequence_number: 11, has_auth_flag: true, payload_data: vec![3, 4] }, 
        NetworkPacket { sequence_number: 12, has_auth_flag: false, payload_data: vec![5] },
    ];

    let (found_flag, checksums) = process_packets(&packets);

    println!("Authentication flag found on any packet: {}", found_flag);
    println!("Valid calculated checksums: {:?}", checksums);
}

