use std::collections::BTreeMap;
use std::error::Error;
use std::fmt;

#[derive(Debug)]
struct KeyValuePair { 
    key: i32,
    value: String
}

impl fmt::Display for KeyValuePair {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Key: {}, Value: {}", self.key, self.value)
    }
}

fn check_for_valid_index(map: &BTreeMap<i32, String>, threshold: i32) -> bool {
    map.iter().any(|(&k, _v)| k > threshold)
}

fn process_and_check_b_tree(data: Vec<(i32, String)>) -> Result<Vec<KeyValuePair>, Box<dyn Error>> {
    let mut b_tree = BTreeMap::new();
    for (k, v) in data {
        b_tree.insert(k, v);
    }

    if check_for_valid_index(&b_tree, 10) {
        let results: Vec<KeyValuePair> = b_tree.iter().map(|(&k, v)| KeyValuePair { key: k, value: v.clone() }).collect();
        Ok(results)
    } else {
        Err("No keys found above the required index threshold".into()) 
    }
}

fn main() {
    let data1 = vec![(5, "A".to_string()), (15, "B".to_string()), (20, "C".to_string())];
    match process_and_check_b_tree(data1) {
        Ok(pairs) => println!("Successfully processed index entries:n{:?}", pairs),
        Err(e) => println!("Error processing index: {}", e),
    }

    let data2 = vec![(1, "X".to_string()), (5, "Y".to_string())];
    match process_and_check_b_tree(data2) {
        Ok(pairs) => println!("Successfully processed index entries:n{:?}", pairs),
        Err(e) => println!("Error processing index: {}", e),
    }
}

use std::collections::HashMap;

struct ConfigSetting {
    name: String,
    value: Result<String, String>,
}

fn validate_setting(setting: &ConfigSetting) -> Result<&str, String> {
    match setting.value.as_ref() {
        Ok(v) if v.contains(":") => Ok("valid_key_found"),
        Ok(_) => Err(format!("Value is empty or malformed for {}", setting.name)),
        Err(e) => Err(format!("Internal parsing error: {}", e)),
    }
}

fn check_all_settings(settings: &[ConfigSetting]) -> Vec<String> {
    let mut all_errors = Vec::new();
    for setting in settings.iter() {
        if let Err(e) = validate_setting(setting) {
            all_errors.push(e);
        }
    }
    all_errors
}

fn check_any_settings(settings: &[ConfigSetting]) -> bool {
    settings.iter().any(|setting| {
        validate_setting(setting).is_ok()
    })
}

fn main() {
    let settings = vec![
        ConfigSetting { name: "timeout".to_string(), value: Ok("10s\":true".to_string()) },
        ConfigSetting { name: "log_level".to_string(), value: Err("Failed to read file".to_string()) },
        ConfigSetting { name: "debug_mode".to_string(), value: Ok("just_a_value".to_string()) },
    ];

    let all_errors = check_all_settings(&settings);
    println!("All validation results collected: {}", all_errors.len());

    let any_valid = settings.iter().any(|s| validate_setting(s).is_ok());
    println!("At least one setting is valid? {}", any_valid);
}
